const urls = [
 'https://news.google.com/rss/search?q=(%22data+breach%22+OR+ransomware+OR+%22cyber+attack%22+OR+hacked)+when:3d&hl=en-US&gl=US&ceid=US:en',
 'https://www.bleepingcomputer.com/feed/'
];
const _i=$input.first()?($input.first().json||{}):{}; const _focus=(_i['Focus (optional)']||_i['Focus']||_i.focus||'').toString().trim();
return urls.map(function(u){ return { json: { url: u, focus: _focus } }; });

const items = $input.all();
const arts = items.map(function(i){ return i.json; }).filter(function(a){ return a && (a.title || a.contentSnippet || a.content); });
function img(a){ try{ if(a.enclosure&&a.enclosure.url) return a.enclosure.url; var c=(a.content||a['content:encoded']||'').toString(); var m=c.match(/<img[^>]+src=["']([^"']+)["']/i); if(m) return m[1]; }catch(e){} return ''; }
const lines = arts.slice(0,20).map(function(a){ var t=(a.title||'').toString(); var s=(a.contentSnippet||a.content||'').toString().replace(/\s+/g,' ').slice(0,200); var u=(a.link||a.url||'').toString(); var im=img(a); return '- '+t+' — '+s+' ('+u+')'+(im?(' IMG='+im):''); });
const digest = lines.length ? lines.join('\n') : 'No breach items retrieved.';
let focus=''; try{ focus=($('Load Sources').first().json.focus||'').toString(); }catch(e){}
return [{ json: { digest: digest, count: arts.length, focus: focus, date: new Date().toISOString().slice(0,10), client: ($env.CLIENT_NAME||'').toString() } }];

