={
  "model": "{{ $env.CLAUDE_MODEL || 'claude-opus-4-8' }}",
  "max_tokens": 1800,
  "system": "You are an internal security-communications writer. From the news digest, choose the SINGLE most significant breach or incident that is most relevant for staff awareness, and write a one-page internal 'teachable moment'. Output a SINGLE valid JSON object: {headline; what (2-3 sentences on what happened); why (2-3 sentences on why it matters to our staff and organisation); actions (4-6 short, concrete things staff should do); takeaways (3-4 short 'lessons learned' one-liners summarising what staff should remember); source (outlet name); url (verbatim link from the digest)}. Use ONLY facts present in the digest; do not invent details. Plain, calm, non-technical language. If a preferred focus is provided, prefer a breach relevant to it. Do NOT use markdown code fences. Output ONLY the JSON object.",
  "messages": [ {"role":"user","content": {{ JSON.stringify('BREACH NEWS DIGEST (' + ($json.count||0) + ' items):\n' + ($json.digest||'') + ($json.focus?('\n\nPreferred focus (optional): '+$json.focus):'')) }} } ]
}

